Here's the complete implementation using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;
    size_t offset = 0;

    // Read packet_id (4 bytes)
    packet.packet_id = hexi::read<uint32_t>(buffer, offset);

    // Read username with length prefix
    packet.username = hexi::read_prefixed_string(buffer, offset);

    // Read scores vector using read_container
    packet.scores = hexi::read_container<std::vector<uint32_t>>(buffer, offset);

    // Read metadata as null-terminated string for zero-copy
    auto metadata_view = hexi::read_null_terminated_string(buffer, offset);
    packet.metadata = std::string(metadata_view);

    // Skip any remaining padding bytes
    // Hexi automatically handles alignment, but we explicitly skip to end if needed
    offset = buffer.size(); // Ensure we've consumed the entire buffer

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;
    size_t offset = 0;

    // Use span() to get zero-copy view of packet_id (first 4 bytes)
    auto packet_id_span = buffer.subspan(0, 4);
    info.packet_id = *reinterpret_cast<const uint32_t*>(packet_id_span.data());
    offset += 4;

    // Read username using prefixed adaptor to get string_view
    info.username = hexi::read_prefixed_string_view(buffer, offset);

    // Skip scores vector: read count then skip the data
    uint32_t score_count = hexi::read<uint32_t>(buffer, offset);
    // Skip the actual score data (each score is 4 bytes)
    offset += score_count * sizeof(uint32_t);

    return info;
}
```

Key implementation details:

1. **`deserialize_packet`**:
   - Uses `hexi::read<uint32_t>` for the packet_id
   - Uses `hexi::read_prefixed_string` for the username with length prefix
   - Uses `hexi::read_container` template for the scores vector
   - Uses `hexi::read_null_terminated_string` for zero-copy metadata reading
   - Converts the string_view to std::string for proper ownership

2. **`extract_packet_info`**:
   - Uses `span::subspan` to get a zero-copy view of the packet_id
   - Uses `hexi::read_prefixed_string_view` for zero-copy username access
   - Reads the score count but skips the actual score data by calculating the offset
   - Returns string_view for zero-copy access to username data

The implementation assumes typical Hexi library conventions for binary serialization/deserialization operations.

