#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use Hexi's span() to read header with zero-copy
    hexi::Reader reader(buffer.data(), buffer.size());

    // Read individual fields from the buffer
    uint8_t version = reader.read_u8();
    uint8_t flags = reader.read_u8();
    uint16_t packet_id = reader.read_u16();

    // Construct and return the PacketHeader
    return PacketHeader{version, flags, packet_id};
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Use Hexi's view() to read null-terminated string with zero-copy
    hexi::Reader reader(buffer.data(), buffer.size());

    // Find the position of the null terminator
    const uint8_t* null_pos = static_cast<const uint8_t*>(std::memchr(buffer.data(), 0, buffer.size()));

    if (null_pos == nullptr) {
        // No null terminator found, return empty string_view
        return std::string_view();
    }

    // Calculate the length of the string (excluding the null terminator)
    size_t length = null_pos - buffer.data();

    // Create a string_view from the buffer data with the calculated length
    return std::string_view(reinterpret_cast<const char*>(buffer.data()), length);
}
