    // Read the data using the buffer adaptor
    adaptor.read(dest_buffer.data(), actual_bytes_to_read);

    return dest_buffer;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Resize the destination buffer if needed to accommodate the source data
    if (dest_buffer.size() < source_data.size()) {
        dest_buffer.resize(source_data.size());
    }

    // Create a buffer adaptor for the destination buffer
