```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <algorithm>

std::vector<uint8_t> peek_buffer_data(const std::vector<uint8_t>& buffer, size_t bytes_to_peek) {
    // Create a buffer adaptor from the input buffer
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());

    // Determine how many bytes we can actually peek (limited by buffer size)
    size_t bytes_available = adaptor.size() - adaptor.rpos();
    size_t bytes_to_copy = std::min(bytes_to_peek, bytes_available);

    // Create destination vector to hold the peeked data
    std::vector<uint8_t> result(bytes_to_copy);

    if (bytes_to_copy > 0) {
        // Use copy() method to peek at data without advancing read pointer
        // The copy() method copies data starting from current read position
        adaptor.copy(result.data(), bytes_to_copy);
    }

    return result;
}
```

