Here's the complete implementation of the function using Hexi library:

```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <stdexcept>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the span
    hexi::buffer_adaptor adaptor(buffer.data(), buffer.size());

    // Check available data using buffer_adaptor methods
    if (adaptor.available() < sizeof(PacketHeader)) {
        throw std::runtime_error("Insufficient data for packet header");
    }

    // Get the read pointer
    const uint8_t* read_ptr = adaptor.data();

    // Create a binary_stream for zero-copy operations
    hexi::binary_stream stream(adaptor);

    // Read header fields using binary_stream's zero-copy operations
    PacketHeader header;

    // Read magic number (uint32_t)
    if (!stream.read(header.magic)) {
        throw std::runtime_error("Failed to read magic number");
    }

    // Read version (uint16_t)
    if (!stream.read(header.version)) {
        throw std::runtime_error("Failed to read version");
    }

    // Read flags (uint16_t)
    if (!stream.read(header.flags)) {
        throw std::runtime_error("Failed to read flags");
    }

    // Alternative approach: Get a zero-copy view of the entire header
    // This demonstrates using buffer_adaptor's pointer methods for a view
    const PacketHeader* header_view = reinterpret_cast<const PacketHeader*>(read_ptr);

    // Verify the view matches what we read through the stream
    // This is just for demonstration - in production you'd use one method or the other
    if (header_view->magic != header.magic || 
        header_view->version != header.version || 
        header_view->flags != header.flags) {
        throw std::runtime_error("Header view verification failed");
    }

    return header;
}
```

