```cpp
#include <hexi/dynamic_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> peek_data_from_buffer(const hexi::dynamic_buffer<block_size>& buffer, size_t bytes_to_peek) {
    // Get the available data size in the buffer
    size_t available_size = buffer.size();

    // Adjust bytes_to_peek if it's larger than available data
    bytes_to_peek = std::min(bytes_to_peek, available_size);

    // Create result vector with the appropriate size
    std::vector<uint8_t> result;
    result.reserve(bytes_to_peek);

    // Create a temporary buffer to read data without advancing the read pointer
    // We'll read the data and then immediately restore the original state
    auto temp_buffer = buffer;

    // Read the requested number of bytes into the result vector
    for (size_t i = 0; i < bytes_to_peek; ++i) {
        uint8_t byte;
        if (temp_buffer.read(&byte, 1)) {
            result.push_back(byte);
        } else {
            // Should not happen since we already checked available_size
            break;
        }
    }

    return result;
}
