```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>

template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    // Clear the buffer before writing new data
    buffer.clear();

    // Convert uint8_t to std::byte and write to buffer
    for (const auto& byte : data) {
        buffer.push_back(static_cast<std::byte>(byte));
    }
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_read) {
    std::vector<uint8_t> result;

    // Determine how many bytes we can actually read (min of requested bytes and available bytes)
    size_t bytes_available = buffer.size();
    size_t bytes_to_copy = (bytes_to_read < bytes_available) ? bytes_to_read : bytes_available;

    // Reserve space in the result vector for efficiency
    result.reserve(bytes_to_copy);

    // Convert std::byte back to uint8_t and read from buffer
    for (size_t i = 0; i < bytes_to_copy; ++i) {
        result.push_back(static_cast<uint8_t>(buffer[i]));
    }

    return result;
}
```

