```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t buffer_size = 1024>
void write_data_to_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, const std::vector<uint8_t>& data) {
    // Clear the buffer before writing new data
    buffer.clear();

    // Use transform to convert and copy all data at once
    std::transform(data.begin(), data.end(), std::back_inserter(buffer),
                   [](uint8_t byte) { return static_cast<std::byte>(byte); });
}

template<size_t buffer_size = 1024>
std::vector<uint8_t> read_data_from_buffer(hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_read) {
    std::vector<uint8_t> result;

    // Determine how many bytes we can actually read
    size_t bytes_available = buffer.size();
    size_t bytes_to_copy = (bytes_to_read < bytes_available) ? bytes_to_read : bytes_available;

    // Reserve space and use transform for efficient conversion
    result.reserve(bytes_to_copy);
    std::transform(buffer.begin(), buffer.begin() + bytes_to_copy, std::back_inserter(result),
                   [](std::byte b) { return static_cast<uint8_t>(b); });

    return result;
}
```

Both implementations handle:
- Type conversion between `uint8_t` and `std::byte`
- Buffer size limitations
- Safe reading (won't read beyond available data)
- Efficient memory management

