Here's the complete implementation of the `preview_buffer_data` function using the Hexi library:

```cpp
#include <hexi/static_buffer.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t buffer_size = 1024>
std::vector<uint8_t> preview_buffer_data(const hexi::static_buffer<std::byte, buffer_size>& buffer, size_t bytes_to_preview) {
    // Get the number of bytes available to read
    size_t available_bytes = buffer.read_available();

    // Determine how many bytes we can actually preview
    size_t bytes_to_copy = std::min(bytes_to_preview, available_bytes);

    if (bytes_to_copy == 0) {
        return {}; // Return empty vector if no data available
    }

    // Create destination vector
    std::vector<uint8_t> result(bytes_to_copy);

    // Peek the data without advancing the read pointer
    // The peek method copies data to destination without modifying read position
    buffer.peek(reinterpret_cast<std::byte*>(result.data()), bytes_to_copy);

    return result;
}
```

