Here's the complete implementation of the varint encoding and decoding functions using the Hexi library:

```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Handle zero case
    if (value == 0) {
        writer.write_byte(0);
        return 1;
    }

    // Encode the value using varint encoding
    while (value > 0) {
        uint8_t byte = value & 0x7F;  // Get lower 7 bits
        value >>= 7;                  // Shift right by 7 bits

        // If there are more bytes to write, set the MSB
        if (value > 0) {
            byte |= 0x80;  // Set continuation bit
        }

        writer.write_byte(byte);
        bytes_written++;
    }

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T result = 0;
    int shift = 0;

    while (true) {
        uint8_t byte = reader.read_byte();
        result |= static_cast<T>(byte & 0x7F) << shift;
        shift += 7;

        // If MSB is not set, this is the last byte
        if ((byte & 0x80) == 0) {
            break;
        }

        // Safety check to prevent infinite loops with malformed data
        if (shift >= static_cast<int>(sizeof(T) * 8)) {
            break;
        }
    }

    return result;
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Encode the value
    hexi::pmc::binary_stream_writer writer(adaptor);
    encode_varint(writer, original_value);

    // Decode the value
    hexi::pmc::binary_stream_reader reader(adaptor);
    T decoded_value = decode_varint<T>(reader);

    // Compare with original
    return original_value == decoded_value;
}
```

This implementation:

1. **`encode_varint`**: Encodes an integer using the standard varint encoding scheme where each byte uses 7 bits for data and 1 bit as a continuation flag.

2. **`decode_varint`**: Decodes a varint-encoded integer by reading bytes until it finds one without the continuation bit set.

3. **`encode_decode_roundtrip`**: Tests the roundtrip by encoding a value, then immediately decoding it and comparing with the original.

The code handles edge cases like zero values and includes safety checks to prevent infinite loops with malformed data. It uses the Hexi library's buffer adaptor and stream classes as required.

