std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer with enough space for the input data
    std::vector<uint8_t> buffer(input_data.size());

    // Create write adaptor and write data
    hexi::pmc::buffer_write_adaptor write_adaptor(buffer.data(), buffer.size());

    // Check available space before writing
    if (write_adaptor.free() >= input_data.size()) {
        write_adaptor.write(input_data.data(), input_data.size());
    }

    // Create read adaptor and read data back
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer.data(), buffer.size());

    // Check readable size
    std::vector<uint8_t> output_data;
    if (read_adaptor.size() >= input_data.size()) {
        output_data.resize(input_data.size());
        read_adaptor.read(output_data.data(), output_data.size());
    }

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    hexi::pmc::buffer_read_adaptor read_adaptor(buffer_data.data(), buffer_data.size());

    std::vector<uint8_t> peeked_data;

    // Use copy() to peek at data without advancing read pointer
    if (read_adaptor.size() >= peek_size) {
        peeked_data.resize(peek_size);
        read_adaptor.copy(peeked_data.data(), peek_size);

        // Alternatively, use read_ptr() to get pointer to current read position
